    10→  CARD = "CARD",
    11→  BANK = "BANK",
    12→  CRYPTO = "CRYPTO",
    13→  PAYPAL = "PAYPAL",
    14→}
    15→
    16→export interface CryptoPaymentMethod {
    17→  id: string;
    18→  network: string;
    19→  address: string;
    20→  label: string;
    21→  isDefault: boolean;
    22→}
    23→
    24→export interface WithdrawalRequest {
    25→  id: string;
    26→  userId: string;
    27→  amount: number;
    28→  currency: string;
    29→  withdrawalMethodType: WithdrawalMethodType;
    30→  status: WithdrawalRequestStatus;
    31→  requestedAt: string;
    32→  processedAt: string | null;
    33→  processedByAdminId: string | null;
    34→  rejectionReason: string | null;
    35→  confirmationFileId: string | null;
    36→  confirmationText: string | null;
    37→  stripeMethod: {
    38→    id: string;
    39→    type: "CARD" | "BANK_ACCOUNT";
    40→    last4: string;
    41→    brand?: string;
    42→    nickname?: string;
    43→  } | null;
    44→  cryptoPaymentMethod: CryptoPaymentMethod | null;
    45→  paypalMethod: {
    46→    id: string;
    47→    email: string;
    48→    type: "PAYPAL_ACCOUNT" | "PAYPAL_BANK";
    49→    nickname?: string;
    50→  } | null;
    51→}
    52→
    53→export interface WithdrawalRequestWithUser extends WithdrawalRequest {
    54→  user: {
    55→    id: string;
    56→    email: string;
    57→    fullName: string;
    58→  };
    59→}
    60→
    61→export interface CreateWithdrawalRequestRequest {
    62→  stripeMethodId: string;
    63→}
    64→
    65→export interface CreatePayPalWithdrawalRequestRequest {
    66→  paypalMethodId: string;
    67→}
    68→
    69→export interface CreateCryptoWithdrawalRequestRequest {
    70→  cryptoPaymentMethodId: string;
    71→}
    72→
    73→export interface CreateWithdrawalRequestResponse extends WithdrawalRequest {}
    74→
    75→export interface WithdrawalRequestListResponse {
    76→  total: number;
    77→  skip: number;
    78→  take: number;
    79→  data: WithdrawalRequestWithUser[];
    80→}
    81→
    82→export interface AdminWithdrawalRequestFilters {
    83→  skip?: number;
    84→  take?: number;
    85→  status?: WithdrawalRequestStatus;
    86→}
    87→
    88→export interface ConfirmWithdrawalRequest {
    89→  file: File;
    90→}
    91→
    92→export const METHOD_TYPE_LABELS: Record<WithdrawalMethodType, string> = {
    93→  CARD: "Card",
    94→  BANK: "Bank Account",
    95→  CRYPTO: "Crypto",
    96→  PAYPAL: "PayPal",
    97→};
