     1→import { getApi } from "@/shared/api/api";
     2→import { API_ROUTES } from "@/shared/config/api-routes";
     3→import type {
     4→  CreateCryptoWithdrawalRequestRequest,
     5→  CreatePayPalWithdrawalRequestRequest,
     6→  CreateWithdrawalRequestRequest,
     7→  CreateWithdrawalRequestResponse,
     8→  WithdrawalRequest,
     9→} from "@/shared/types/withdrawal-request.types";
    10→
    11→export const withdrawalRequestsService = {
    12→  async createRequest(
    13→    request: CreateWithdrawalRequestRequest,
    14→  ): Promise<CreateWithdrawalRequestResponse> {
    15→    const api = await getApi();
    16→
    17→    const { data } = await api.post<CreateWithdrawalRequestResponse>(
    18→      API_ROUTES.WITHDRAWAL_REQUESTS.CREATE,
    19→      request,
    20→    );
    21→
    22→    return data;
    23→  },
    24→
    25→  async createCryptoRequest(
    26→    request: CreateCryptoWithdrawalRequestRequest,
    27→  ): Promise<CreateWithdrawalRequestResponse> {
    28→    const api = await getApi();
    29→
    30→    const { data } = await api.post<CreateWithdrawalRequestResponse>(
    31→      API_ROUTES.WITHDRAWAL_REQUESTS.CREATE_CRYPTO,
    32→      request,
    33→    );
    34→
    35→    return data;
    36→  },
    37→
    38→  async createPayPalRequest(
    39→    request: CreatePayPalWithdrawalRequestRequest,
    40→  ): Promise<CreateWithdrawalRequestResponse> {
    41→    const api = await getApi();
    42→
    43→    const { data } = await api.post<CreateWithdrawalRequestResponse>(
    44→      API_ROUTES.WITHDRAWAL_REQUESTS.CREATE_PAYPAL,
    45→      request,
    46→    );
    47→
    48→    return data;
    49→  },
    50→
    51→  async listRequests(): Promise<WithdrawalRequest[]> {
    52→    const api = await getApi();
    53→
    54→    const { data } = await api.get<WithdrawalRequest[]>(
    55→      API_ROUTES.WITHDRAWAL_REQUESTS.LIST,
    56→    );
    57→
    58→    return data;
    59→  },
    60→
    61→  async getRequest(id: string): Promise<WithdrawalRequest> {
    62→    const api = await getApi();
    63→
    64→    const { data } = await api.get<WithdrawalRequest>(
    65→      API_ROUTES.WITHDRAWAL_REQUESTS.GET(id),
    66→    );
    67→
    68→    return data;
    69→  },
    70→};
