     1→import { getApi } from "@/shared/api/api";
     2→import { API_ROUTES } from "@/shared/config/api-routes";
     3→import { formatCentsToUSD } from "@/shared/lib/utils/price-formatter";
     4→import type {
     5→  SavedCryptoAddress,
     6→  SavedStripeMethod,
     7→  Wallet,
     8→  WalletTransactionsResponse,
     9→  WalletTransactionsSummaryResponseDto,
    10→} from "@/shared/types/payment.types";
    11→import { cryptoAddressesService } from "./crypto-addresses.service";
    12→import { paypalMethodsService } from "./paypal-methods.service";
    13→import { stripeMethodsService } from "./stripe-methods.service";
    14→
    15→export interface WalletWithFormatted extends Wallet {
    16→  balanceFormatted: string;
    17→  usdtBalanceFormatted: string;
    18→}
    19→
    20→export interface SavedPaymentMethodMapped
    21→  extends Omit<SavedStripeMethod, "type"> {
    22→  type: "card" | "bank";
    23→}
    24→
    25→export interface WalletInfoResponse {
    26→  balance: number;
    27→  balanceDollars: number;
    28→  balanceFormatted: string;
    29→  usdtBalanceFormatted: string;
    30→  currency: string;
    31→  lastActivityAt?: string;
    32→  savedPaymentMethods: SavedPaymentMethodMapped[];
    33→  savedCryptoAddresses: SavedCryptoAddress[];
    34→}
    35→
    36→export interface TransactionFilters {
    37→  limit?: number;
    38→  skip?: number;
    39→}
    40→
    41→export interface WithdrawRequest {
    42→  amount: number;
    43→  paymentMethodId: string;
    44→  type: "fiat" | "crypto";
    45→}
    46→
    47→export interface WithdrawResponse {
    48→  transactionId: string;
    49→  status: string;
    50→  amount: number;
    51→  estimatedArrival?: string;
    52→}
    53→
    54→export interface CalculateWithdrawFeeRequest {
    55→  amount: number;
    56→  type: "fiat" | "crypto";
    57→}
    58→
    59→export interface CalculateWithdrawFeeResponse {
    60→  amount: number;
    61→  feeAmount: number;
    62→  totalAmount: number;
    63→  feePercentage: number;
    64→}
    65→
    66→export const walletService = {
    67→  async getWallet(): Promise<Wallet> {
    68→    const api = await getApi();
    69→    const { data } = await api.get<Wallet>(API_ROUTES.WALLET.GET);
    70→    return data;
    71→  },
    72→
    73→  async getTransactions(
    74→    filters?: TransactionFilters,
    75→  ): Promise<WalletTransactionsResponse> {
    76→    const api = await getApi();
    77→    const { data } = await api.get<WalletTransactionsResponse>(
    78→      API_ROUTES.WALLET.TRANSACTIONS,
    79→      {
    80→        params: {
    81→          limit: filters?.limit ?? 50,
    82→          skip: filters?.skip ?? 0,
    83→        },
    84→      },
    85→    );
    86→    return data;
    87→  },
    88→
    89→  async getTransactionsSummary(): Promise<WalletTransactionsSummaryResponseDto> {
    90→    const api = await getApi();
    91→    const { data } = await api.get<WalletTransactionsSummaryResponseDto>(
    92→      API_ROUTES.WALLET.TRANSACTIONS_SUMMARY,
    93→    );
    94→    return data;
    95→  },
    96→
    97→  async getWalletInfo(): Promise<WalletInfoResponse> {
    98→    const [wallet, savedPaymentMethods, savedCryptoAddresses] =
    99→      await Promise.all([
   100→        this.getWallet(),
   101→        stripeMethodsService.listMethods(),
   102→        cryptoAddressesService.listAddresses(),
   103→      ]);
   104→
   105→    return {
   106→      ...wallet,
   107→      balanceFormatted: formatCentsToUSD(wallet.balance),
   108→      usdtBalanceFormatted: `USDT ${formatCentsToUSD(wallet.balance)}`,
   109→      savedPaymentMethods: savedPaymentMethods.map((method) => ({
   110→        ...method,
   111→        type: method.type === "CARD" ? ("card" as const) : ("bank" as const),
   112→      })),
   113→      savedCryptoAddresses,
   114→    };
   115→  },
   116→
   117→  async getPayPalMethods() {
   118→    return paypalMethodsService.listMethods();
   119→  },
   120→
   121→  async withdraw(request: WithdrawRequest): Promise<WithdrawResponse> {
   122→    const api = await getApi();
   123→    const { data } = await api.post<WithdrawResponse>(
   124→      API_ROUTES.WALLET.WITHDRAW,
   125→      request,
   126→    );
   127→    return data;
   128→  },
   129→
   130→  async calculateWithdrawFee(
   131→    request: CalculateWithdrawFeeRequest,
   132→  ): Promise<CalculateWithdrawFeeResponse> {
   133→    const api = await getApi();
   134→    const { data } = await api.post<CalculateWithdrawFeeResponse>(
   135→      API_ROUTES.WALLET.CALCULATE_WITHDRAW_FEE,
   136→      request,
   137→    );
   138→    return data;
   139→  },
   140→};
