     1→"use client";
     2→
     3→import { zodResolver } from "@hookform/resolvers/zod";
     4→import { type FieldValues, useForm } from "react-hook-form";
     5→import { LogoUsd } from "react-ionicons";
     6→import { z } from "zod";
     7→
     8→import { useWalletInfo } from "@/shared/api/query-hooks/use-wallet";
     9→import { Badge } from "@/shared/ui/badge";
    10→import { Button } from "@/shared/ui/button";
    11→import {
    12→  Dialog,
    13→  DialogCloseButton,
    14→  DialogContent,
    15→  DialogTitle,
    16→} from "@/shared/ui/dialog";
    17→import { Form } from "@/shared/ui/form/form";
    18→import { FormControl } from "@/shared/ui/form/form-control";
    19→import { FormField } from "@/shared/ui/form/form-field";
    20→import { FormItem } from "@/shared/ui/form/form-item";
    21→import { FormMessage } from "@/shared/ui/form/form-message";
    22→import { Input } from "@/shared/ui/input";
    23→import { Label } from "@/shared/ui/label";
    24→import { toast } from "@/shared/ui/notification";
    25→import { RadioGroup, RadioGroupItem } from "@/shared/ui/radio";
    26→import {
    27→  formatDollarsToUSD,
    28→  dollarsToCents,
    29→} from "@/shared/lib/utils/price-formatter";
    30→
    31→const withdrawSchema = z.object({
    32→  amount: z
    33→    .string()
    34→    .min(1, "Amount is required")
    35→    .refine(
    36→      (val) => !Number.isNaN(Number(val)) && Number(val) > 0,
    37→      "Amount must be positive",
    38→    ),
    39→  paymentMethodId: z.string().min(1, "Please select a crypto wallet"),
    40→});
    41→
    42→type WithdrawForm = z.infer<typeof withdrawSchema>;
    43→
    44→interface WithdrawFundsModalProps {
    45→  isOpen: boolean;
    46→  onClose: () => void;
    47→  onSuccess?: () => void;
    48→}
    49→
    50→export function WithdrawFundsModal({
    51→  isOpen,
    52→  onClose,
    53→  onSuccess,
    54→}: WithdrawFundsModalProps) {
    55→  const { data: walletInfo } = useWalletInfo();
    56→
    57→  const form = useForm<WithdrawForm>({
    58→    resolver: zodResolver(withdrawSchema),
    59→    defaultValues: {
    60→      amount: "",
    61→      paymentMethodId: "",
    62→    },
    63→  });
    64→
    65→  const selectedMethodId = form.watch("paymentMethodId");
    66→  const amount = form.watch("amount");
    67→
    68→  async function handleWithdraw(data: WithdrawForm) {
    69→    const amountCents = dollarsToCents(Number(data.amount));
    70→
    71→    if (walletInfo && amountCents > walletInfo.balance) {
    72→      toast.error("Insufficient balance");
    73→
    74→      return;
    75→    }
    76→
    77→    try {
    78→      // TODO: Implement withdraw mutation when backend endpoint is ready
    79→      toast.info("Withdrawal feature coming soon");
    80→      form.reset();
    81→      onSuccess?.();
    82→      onClose();
    83→    } catch {
    84→      toast.error("Failed to withdraw");
    85→    }
    86→  }
    87→
    88→  if (!walletInfo) return null;
    89→
    90→  const cryptoAddresses = walletInfo.savedCryptoAddresses;
    91→
    92→  return (
    93→    <Dialog open={isOpen} onOpenChange={onClose}>
    94→      <DialogContent className="max-h-[95vh] w-[600px] gap-0 p-[30px]">
    95→        <div className="flex flex-col gap-[30px]">
    96→          <div className="flex items-center justify-between">
    97→            <DialogTitle className="font-bold font-serif text-2xl text-foreground leading-[1.199em]">
    98→              Withdraw Funds
    99→            </DialogTitle>
   100→            <DialogCloseButton />
   101→          </div>
   102→
   103→          <div className="flex items-center justify-between rounded-[10px] bg-secondary/10 p-4">
   104→            <span className="font-serif text-base text-foreground">
   105→              Available Balance
   106→            </span>
   107→            <div className="flex items-center gap-4">
   108→              <span className="font-bold font-serif text-foreground text-lg">
   109→                {walletInfo.usdtBalanceFormatted}
   110→              </span>
   111→              <span className="font-serif text-base text-foreground">
   112→                {walletInfo.balanceFormatted}
   113→              </span>
   114→            </div>
   115→          </div>
   116→
   117→          <Form {...form}>
   118→            <form
   119→              onSubmit={form.handleSubmit(handleWithdraw)}
   120→              className="flex flex-col gap-[30px]"
   121→            >
   122→              <div
   123→                className="flex flex-col gap-[25px] overflow-y-auto pr-2"
   124→                style={{ maxHeight: "calc(95vh - 400px)" }}
   125→              >
   126→                <div className="flex flex-col gap-[15px]">
   127→                  <h3 className="font-serif text-foreground text-lg leading-[1.54em]">
   128→                    Select Crypto Wallet:
   129→                  </h3>
   130→
   131→                  <FormField
   132→                    control={form.control}
   133→                    name="paymentMethodId"
   134→                    render={({ field }: { field: FieldValues }) => (
   135→                      <FormItem>
   136→                        <FormControl>
   137→                          {cryptoAddresses.length === 0 ? (
   138→                            <div className="rounded-[10px] border border-input py-8 text-center text-muted-foreground text-sm">
   139→                              No crypto wallets available.
   140→                              <br />
   141→                              Please add one first.
   142→                            </div>
   143→                          ) : (
   144→                            <RadioGroup
   145→                              value={field.value}
   146→                              onValueChange={field.onChange}
   147→                              className="gap-3"
   148→                            >
   149→                              {cryptoAddresses.map((address) => {
   150→                                const networkDisplay =
   151→                                  address.network === "TRON"
   152→                                    ? "TRC-20"
   153→                                    : address.network;
   154→
   155→                                return (
   156→                                  <label
   157→                                    key={address.id}
   158→                                    className="flex cursor-pointer items-center gap-3 rounded-[10px] border border-input p-3 transition-colors hover:bg-secondary/20"
   159→                                  >
   160→                                    <RadioGroupItem value={address.id} />
   161→
   162→                                    <div className="flex h-10 w-[50px] shrink-0 items-center justify-center rounded-[8px] border border-input bg-gradient-to-br from-primary/5 to-primary/10">
   163→                                      <LogoUsd
   164→                                        width="24px"
   165→                                        height="24px"
   166→                                        className="text-primary"
   167→                                      />
   168→                                    </div>
   169→
   170→                                    <div className="flex-1">
   171→                                      <div className="flex items-center gap-2">
   172→                                        <span className="font-bold font-serif text-base text-foreground">
   173→                                          {address.label}
   174→                                        </span>
   175→                                        {address.isDefault && (
   176→                                          <Badge
   177→                                            variant="primary"
   178→                                            className="h-fit text-xs"
   179→                                          >
   180→                                            Default
   181→                                          </Badge>
   182→                                        )}
   183→                                      </div>
   184→                                      <div className="mt-1 flex items-center gap-2">
   185→                                        <Badge
   186→                                          variant="outline"
   187→                                          className="h-fit px-1.5 py-0 text-[10px]"
   188→                                        >
   189→                                          {networkDisplay}
   190→                                        </Badge>
   191→                                        <span className="font-mono text-muted-foreground text-xs">
   192→                                          {address.address.slice(0, 8)}...
   193→                                          {address.address.slice(-6)}
   194→                                        </span>
   195→                                      </div>
   196→                                    </div>
   197→                                  </label>
   198→                                );
   199→                              })}
   200→                            </RadioGroup>
   201→                          )}
   202→                        </FormControl>
   203→                        <FormMessage />
   204→                      </FormItem>
   205→                    )}
   206→                  />
   207→                </div>
   208→
   209→                <FormField
   210→                  control={form.control}
   211→                  name="amount"
   212→                  render={({
   213→                    field,
   214→                    fieldState,
   215→                  }: {
   216→                    field: FieldValues;
   217→                    fieldState: FieldValues;
   218→                  }) => (
   219→                    <FormItem className="flex flex-col gap-2">
   220→                      <Label className="font-serif text-base text-foreground leading-[1.375em]">
   221→                        Withdrawal Amount (USD)
   222→                      </Label>
   223→                      <FormControl>
   224→                        <Input
   225→                          {...field}
   226→                          type="number"
   227→                          step="0.01"
   228→                          placeholder="Enter amount"
   229→                          className="rounded-input border-input px-input-200 py-input-100 font-serif text-sm leading-[1.2em]"
   230→                          aria-invalid={!!fieldState.error}
   231→                        />
   232→                      </FormControl>
   233→                      <FormMessage />
   234→                    </FormItem>
   235→                  )}
   236→                />
   237→
   238→                {amount && Number(amount) > 0 && (
   239→                  <div className="flex flex-col gap-3 rounded-[10px] border border-primary/20 bg-primary/5 p-4">
   240→                    <div className="flex justify-between">
   241→                      <span className="font-serif text-foreground text-sm">
   242→                        Withdrawal Amount:
   243→                      </span>
   244→                      <span className="font-bold font-serif text-foreground text-sm">
   245→                        {formatDollarsToUSD(Number(amount))}
   246→                      </span>
   247→                    </div>
   248→                    <p className="font-serif text-muted-foreground text-xs">
   249→                      * Fees and total will be calculated by the backend
   250→                    </p>
   251→                    <p className="font-serif text-muted-foreground text-xs">
   252→                      * Estimated arrival: 1-3 business days
   253→                    </p>
   254→                  </div>
   255→                )}
   256→              </div>
   257→
   258→              <Button
   259→                type="submit"
   260→                disabled={
   261→                  !(selectedMethodId && amount) ||
   262→                  Number(amount) <= 0 ||
   263→                  (walletInfo &&
   264→                    dollarsToCents(Number(amount)) > walletInfo.balance)
   265→                }
   266→                className="h-auto w-full rounded-[15px] px-[30px] py-[10px]"
   267→                size="default"
   268→              >
   269→                Withdraw Funds
   270→              </Button>
   271→            </form>
   272→          </Form>
   273→        </div>
   274→      </DialogContent>
   275→    </Dialog>
   276→  );
   277→}
   278→

