    24→interface RejectOfferModalProps {
    25→  isOpen: boolean;
    26→  onClose: () => void;
    27→  request: BuybackRequestDetail | null;
    28→  offerType: "pre-auth" | "post-auth";
    29→}
    30→
    31→const rejectOfferSchema = z.object({
    32→  reason: z.string().min(1, "Please provide a reason for rejection"),
    33→});
    34→
    35→type RejectOfferFormData = z.infer<typeof rejectOfferSchema>;
    36→
    37→export function RejectOfferModal({
    38→  isOpen,
    39→  onClose,
    40→  request,
    41→  offerType,
    42→}: RejectOfferModalProps) {
    43→  const [isLoading, setIsLoading] = useState(false);
    44→
    45→  const rejectPreAuthOffer = useRejectPreAuthOffer();
    46→  const rejectPostAuthOffer = useRejectPostAuthOffer();
    47→
    48→  const form = useForm<RejectOfferFormData>({
    49→    resolver: zodResolver(rejectOfferSchema),
    50→    defaultValues: {
    51→      reason: "",
    52→    },
    53→  });
    54→
    55→  if (!request) return null;
    56→
    57→  const onSubmit = async (data: RejectOfferFormData) => {
    58→    setIsLoading(true);
    59→
    60→    try {
    61→      if (offerType === "pre-auth") {
    62→        await rejectPreAuthOffer.mutateAsync({
    63→          id: request.id,
    64→          data: { reason: data.reason },
    65→        });
    66→      } else {
    67→        await rejectPostAuthOffer.mutateAsync({
    68→          id: request.id,
    69→          data: { reason: data.reason },
    70→        });
    71→      }
    72→
    73→      toast.success("Offer rejected successfully", {
    74→        description: "Your rejection has been recorded.",
    75→      });
    76→      handleClose();
    77→    } catch {
    78→      toast.error("Failed to reject offer", {
    79→        description: "Please try again later.",
    80→      });
    81→    } finally {
    82→      setIsLoading(false);
    83→    }
    84→  };
    85→
    86→  const handleClose = () => {
    87→    form.reset();
    88→    onClose();
    89→  };
    90→
    91→  return (
    92→    <Dialog open={isOpen} onOpenChange={(open) => !open && handleClose()}>
    93→      <DialogContent className="w-[459px] gap-0 rounded-[10px] p-0">
    94→        <Form {...form}>
    95→          <form
    96→            onSubmit={form.handleSubmit(onSubmit)}
    97→            className="flex flex-col items-center gap-5 p-5"
    98→          >
    99→            <div className="flex w-full flex-col gap-[25px]">
   100→              <div className="flex w-full items-center justify-between">
   101→                <h2 className="font-bold font-serif text-base leading-[1.199em]">
   102→                  Confirmation
   103→                </h2>
   104→                <button
   105→                  type="button"
   106→                  onClick={handleClose}
   107→                  className="flex h-[25px] w-[25px] shrink-0 items-center justify-center transition-opacity hover:opacity-70"
   108→                >
   109→                  <CloseOutline width="25px" height="25px" color="#21272A" />
   110→                </button>
   111→              </div>
   112→
   113→              <div className="h-px w-full bg-primary" />
   114→            </div>
   115→
   116→            <div className="flex w-full flex-col gap-[30px]">
   117→              <div className="flex w-full flex-col gap-[30px]">
   118→                <div className="flex w-full flex-col items-center justify-center">
   119→                  <p className="flex h-[25px] w-full items-center justify-center text-center font-bold font-serif text-base leading-[1.199em]">
   120→                    Are you sure you want to reject this BuyBack offer?
   121→                  </p>
   122→                </div>
   123→
   124→                <FormField
   125→                  control={form.control}
   126→                  name="reason"
   127→                  render={({ field, fieldState }) => (
   128→                    <FormItem className="w-full">
   129→                      <FormLabel className="flex h-[21px] items-center font-serif text-sm leading-[1.571em]">
   130→                        Reason for rejection
   131→                      </FormLabel>
   132→                      <FormControl>
   133→                        <Input
   134→                          placeholder="Write a reason"
   135→                          className="flex-1 font-serif text-sm leading-[1.199em]"
   136→                          aria-invalid={!!fieldState.error}
   137→                          {...field}
   138→                        />
   139→                      </FormControl>
   140→                      <FormMessage />
   141→                    </FormItem>
   142→                  )}
   143→                />
   144→              </div>
   145→
   146→              <div className="flex w-full items-center justify-center gap-2.5">
   147→                <Button
   148→                  type="button"
   149→                  size="modal"
   150→                  variant="outline"
   151→                  onClick={handleClose}
   152→                  disabled={isLoading}
   153→                  className="flex-1"
   154→                >
   155→                  Cancel
   156→                </Button>
   157→                <Button
   158→                  type="submit"
   159→                  size="modal"
   160→                  loading={isLoading}
   161→                  className="flex-1"
   162→                >
   163→                  Submit
   164→                </Button>
   165→              </div>
   166→            </div>
   167→          </form>
   168→        </Form>
   169→      </DialogContent>
   170→    </Dialog>
   171→  );
   172→}
